class Provider(ABC, Generic[InterfaceClient]):
    """Provider 提供认证后的 API 客户端"""

    @property
    @abstractmethod
    def name(self) -> str: ...

    @property
    @abstractmethod
    def base_url(self) -> str: ...

    @property
    @abstractmethod
    def client(self) -> InterfaceClient: ...

    @staticmethod
    def model_profile(model_name: str) -> ModelProfile | None:
        return None

def infer_model(
    model: Model | KnownModelName | str,
    provider_factory: Callable[[str], Provider[Any]] = infer_provider
) -> Model:
    """从模型名称推断并创建 Model 实例"""
    if isinstance(model, Model):
        return model

    # 解析 provider:model 格式
    provider_name, model_name = parse_model_id(model)

    # 获取 Provider 实例
    provider = provider_factory(provider_name)

    # 根据提供商类型创建对应 Model
    if provider_name == 'anthropic':
        return AnthropicModel(model_name, provider=provider)
    elif provider_name in ('openai', 'groq', 'cerebras'):
        return OpenAIChatModel(model_name, provider=provider)
    # ... 更多提供商
    else:
        raise UserError(f'Unknown model: {model}')

